class Circle {
  constructor(radius) {
    this.radius = radius;
  }
  area()      { return Math.PI * this.radius ** 2; }
  perimeter() { return 2 * Math.PI * this.radius; }
}
// Any object with area() + perimeter() satisfies the "Shape" contract
